CREATE OR REPLACE FUNCTION public.board_authority_select(_user_no integer)
 RETURNS TABLE(id integer, userno integer, name character varying, moduserno integer, menutitle character varying, authority character varying, departmentid integer)
 LANGUAGE plpgsql
AS $function$
#variable_conflict use_column
DECLARE
    _rowindex integer;
    _maxindex integer;
    _departno integer;
    _parentno integer;
BEGIN


		CREATE TEMP TABLE _ListOfDepartNos (
			DepartNo	INT
		) ON COMMIT DROP;

		CREATE TEMP TABLE _BelongToDepartments (
			RowNum		serial,
			DepartNo	INT,
			ParentNo	INT
		) ON COMMIT DROP;

		INSERT INTO _BelongToDepartments
		SELECT DepartNo, ParentNo FROM Organization_Departments
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment
			WHERE UserNo = board_authority_select._user_no
		);


		_RowIndex := 1;
		_MaxIndex := (SELECT MAX(RowNum) FROM _BelongToDepartments);
		WHILE _RowIndex <= _MaxIndex LOOP

			SELECT DepartNo, ParentNo INTO _departno, _parentno FROM _BelongToDepartments

			WHERE RowNum = _RowIndex;

			INSERT INTO _ListOfDepartNos
			SELECT _DepartNo;

			WHILE _ParentNo != 0 LOOP

				SELECT DepartNo, ParentNo INTO _departno, _parentno FROM Organization_Departments
				WHERE DepartNo = _ParentNo;

				INSERT INTO _ListOfDepartNos
				SELECT _DepartNo;

			END LOOP;

			_RowIndex := _RowIndex + 1;
		END LOOP;

RETURN QUERY
SELECT  bu.USERGROUP_ID AS "Id",
		bu.USER_NO AS "UserNo",
		CASE
		  WHEN bu.USER_NO >0  THEN ou.Name
		  ELSE od.Name || ' (' || od.Name_EN || ')'
		END AS "Name" ,
		ou.ModUserNo,
		(Select MENU_TITLE FROM Board_Menu WHERE MENU_IDX =bu.MENU_ID) as MenuTitle,
   (Select AUTH_GRP_NM FROM Board_AuthoGroup WHERE AUTH_GRP_ID =bu.AUTH_GRP_ID) as Authority,
		bu.DEPARTMENT_ID AS "DepartmentId"

   --ou.UserNo,
   --ou.Name,
   --ou.ModUserNo,
   --(Select MENU_TITLE FROM Board_Menu WHERE MENU_IDX =bu.MENU_ID) as MenuTitle,
   --(Select AUTH_GRP_NM FROM Board_AuthoGroup WHERE AUTH_GRP_ID =bu.AUTH_GRP_ID) as Authority
  FROM
  Board_UserByGroup bu LEFT JOIN
	  Organization_Users ou
	  on ou.UserNo = bu.USER_NO inner join Board_AuthoGroup ag on bu.AUTH_GRP_ID=ag.AUTH_GRP_ID

	  LEFT JOIN Organization_Departments od on od.DepartNo=bu.DEPARTMENT_ID
  where (UserNo=board_authority_select._user_no OR DEPARTMENT_ID IN (SELECT DepartNo FROM _ListOfDepartNos)) and MENU_ID=(Select MENU_IDX From Board_Menu Where MENU_ID='MAIN')
  AND NOT (bu.USER_NO >0 AND ou.UserNo Is null)
  ORDER BY ag.AUTH_GRP_ID ASC;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_deletedepartallowaccess(_listallowaccessno character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _departno integer;
    _itemno integer;
    _itemtype integer;
BEGIN


	CREATE TEMP TABLE Board_DepartAllowAccess ON COMMIT DROP AS SELECT * FROM Board_DepartAllowAccess
	WHERE AllowAccessNo IN(SELECT unnest(string_to_array(_ListAllowAccessNo, ','))::integer);




	WHILE (Select Count(*) From Board_DepartAllowAccess) > 0 LOOP
		SELECT DA.DepartNo, DA.ItemNo, DA.ItemType INTO _departno, _itemno, _itemtype FROM Board_DepartAllowAccess DA;
		IF _ItemType=2 THEN
			DELETE FROM Board_DepartAllowAccess WHERE ItemNo=_ItemNo AND ItemType=_ItemType AND DepartNo=_DepartNo;
		ELSE
			CREATE TEMP TABLE FolderTemp ON COMMIT DROP AS WITH RECURSIVE FolderNos AS (
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo =_ItemNo
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderNos FN ON FN.FolderNo = CF.ParentNo AND CF.Enabled = TRUE
			)SELECT * FROM FolderNos;
			DELETE FROM Board_DepartAllowAccess WHERE ItemType=1 AND DepartNo=_DepartNo AND
			ItemNo IN (SELECT FolderNo FROM FolderTemp);
			DELETE FROM Board_DepartAllowAccess WHERE ItemType=2 AND DepartNo=_DepartNo AND
			ItemNo IN (SELECT BB.BoardNo FROM Board_Boards BB INNER JOIN FolderTemp BF ON BF.FolderNo=bb.FolderNo);
			DROP TABLE IF EXISTS FolderTemp;
		END IF;
		DELETE FROM Board_DepartAllowAccess WHERE ItemNo=_ItemNo AND ItemType=_ItemType AND DepartNo=_DepartNo;
	END LOOP;
	DROP TABLE IF EXISTS Board_DepartAllowAccess;
END;
$function$

