$function$

CREATE OR REPLACE FUNCTION public.board_deletereply(_replyno bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _contentno bigint;
    _orderno integer;
BEGIN




	SELECT ContentNo, OrderNo INTO _contentno, _orderno FROM Board_Replies

	WHERE ReplyNo = board_deletereply._replyno;

	UPDATE Board_Replies SET OrderNo = OrderNo - 1
	WHERE ContentNo = _ContentNo AND OrderNo > _OrderNo;

	DELETE FROM Board_Replies WHERE ReplyNo = board_deletereply._replyno;

	UPDATE Board_Contents SET ReplyCount = ReplyCount -1
	WHERE ContentNo = _ContentNo;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_downboard(_boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _parentno integer;
    _sortno integer;
    _tempno integer;
    _ranktempno integer;
BEGIN




SELECT FolderNo, SortNo INTO _parentno, _sortno FROM Board_Boards where BoardNo= board_downboard._boardno;
_RANKTEMPNO := 1;
FOR _tempno IN SELECT  BoardNo from Board_Boards WHERE _PARENTNO=FolderNo AND Enabled = TRUE ORDER BY SortNo ASC,BoardNo ASC LOOP
		UPDATE Board_Boards SET SortNo = _RANKTEMPNO WHERE _TEMPNO=BoardNo;

		IF _TEMPNO=board_downboard._boardno THEN
			_SORTNO := _RANKTEMPNO;
		END IF;
		_RANKTEMPNO := _RANKTEMPNO+1;
		   END LOOP;
UPDATE Board_Boards SET SortNo = _SORTNO WHERE _SORTNO = SortNo - 1 AND FolderNo=_PARENTNO AND Enabled = TRUE;
UPDATE Board_Boards SET SortNo = _SORTNO + 1 WHERE BoardNo= board_downboard._boardno;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_downboardbyuser(_boardno integer DEFAULT 1093, _userno integer DEFAULT 70, _isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _curentno integer;
    _parentno integer;
    _upno integer;
    _isboard boolean;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

SELECT SortNo, FolderNo INTO _curentno, _parentno FROM Board_Boards WHERE  BoardNo = board_downboardbyuser._boardno;

SELECT T.SortNo, T.IsBoard INTO _upno, _isboard FROM (
SELECT BoardNo AS No, SortNo,TRUE AS IsBoard FROM Board_Boards B
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_downboardbyuser._userno
WHERE  B.Enabled = TRUE  AND (_IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo<_CurentNo AND _ParentNo=B.FolderNo
UNION ALL
SELECT BF.FolderNo AS No, SortNo,FALSE AS IsBoard
FROM  Board_Folders BF
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_downboardbyuser._userno
WHERE  BF.SortNo<_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled = TRUE AND (_IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
ORDER BY SortNo DESC) T ORDER BY T.SortNo DESC;











--SELECT SortNo, IsBoard INTO downno, isboard FROM TEMPUPDATE
IF _UpNo >0 AND _IsBoard= TRUE THEN
	UPDATE Board_Boards SET SortNo=_CurentNo WHERE SortNo=_UpNo;
	UPDATE Board_Boards SET SortNo=_UpNo WHERE BoardNo = board_downboardbyuser._boardno ;
IF _UpNo >0 AND _IsBoard= FALSE THEN
	UPDATE Board_Folders SET SortNo=_CurentNo WHERE SortNo=_UpNo;
	UPDATE Board_Boards SET SortNo=_UpNo WHERE BoardNo = board_downboardbyuser._boardno ;

END IF;
END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_downfolder(_folderno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _parentno integer;
    _sortno integer;
    _foldertempno integer;
    _ranktempno integer;
BEGIN




SELECT ParentNo, SortNo INTO _parentno, _sortno FROM Board_Folders where FolderNo= board_downfolder._folderno;
_RANKTEMPNO := 1;
FOR _foldertempno IN SELECT FolderNo from Board_Folders WHERE _PARENTNO=ParentNo AND Enabled = TRUE ORDER BY SortNo ASC, FolderNo ASC LOOP
		UPDATE Board_Folders SET SortNo = _RANKTEMPNO WHERE _FOLDERTEMPNO=FolderNo;

		IF _FOLDERTEMPNO=board_downfolder._folderno THEN
			_SORTNO := _RANKTEMPNO;
		END IF;

		_RANKTEMPNO := _RANKTEMPNO + 1;
		   END LOOP;
UPDATE Board_Folders SET SortNo = _SORTNO WHERE _SORTNO = SortNo - 1 AND ParentNo=_PARENTNO AND Enabled = TRUE;
UPDATE Board_Folders SET SortNo = _SORTNO+1 WHERE FolderNo = board_downfolder._folderno;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_downfolderbyuser(_folderno integer, _userno integer DEFAULT 70, _isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _curentno integer;
    _parentno integer;
    _upno integer;
    _isfolder boolean;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

SELECT SortNo, ParentNo INTO _curentno, _parentno FROM Board_Folders WHERE  FolderNo = board_downfolderbyuser._folderno;

SELECT T.SortNo, T.IsFolder INTO _upno, _isfolder FROM (
SELECT BoardNo AS No, SortNo,FALSE AS IsFolder FROM Board_Boards B
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_downfolderbyuser._userno
WHERE  B.Enabled = TRUE  AND (_IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo<_CurentNo AND _ParentNo=B.FolderNo
UNION ALL
SELECT BF.FolderNo AS No, SortNo,TRUE AS IsFolder
FROM  Board_Folders BF
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_downfolderbyuser._userno
WHERE  BF.SortNo<_CurentNo AND BF.Enabled = TRUE AND (_IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
ORDER BY SortNo DESC) T ORDER BY T.SortNo DESC;











--SELECT SortNo, IsBoard INTO downno, isboard FROM TEMPUPDATE
IF _UpNo >0 AND _IsFolder= TRUE THEN
	UPDATE Board_Folders SET SortNo=_CurentNo WHERE SortNo=_UpNo;
	UPDATE Board_Folders SET SortNo=_UpNo WHERE FolderNo = board_downfolderbyuser._folderno ;
IF _UpNo >0 AND _IsFolder= FALSE THEN
	UPDATE Board_Boards SET SortNo=_CurentNo WHERE SortNo=_UpNo;
	UPDATE Board_Folders SET SortNo=_UpNo WHERE FolderNo = board_downfolderbyuser._folderno ;

END IF;
END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_downmultilwidget(_userno integer, _boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _sorttemp integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	SELECT Sort INTO _sorttemp FROM Board_MultiBoardWidget WHERE  BoardNo = board_downmultilwidget._boardno  AND IsDelete= FALSE;
	CREATE TEMP TABLE WidgetTemp ON COMMIT DROP AS SELECT No,Sort FROM Board_MultiBoardWidget
	WHERE IsDelete= FALSE AND Sort<=_SortTemp
	ORDER BY Sort DESC;
	UPDATE Board_MultiBoardWidget AS BW SET Sort=(SELECT /* /* TOP 1 */ */ T.Sort FROM WidgetTemp T WHERE BW.No <>T.No),ModUserNo= board_downmultilwidget._userno,ModDate=NOW() FROM WidgetTemp T WHERE T.No=BW.No;
END;
$function$

