CREATE OR REPLACE FUNCTION public.board_getdepartandpositionname(_departno integer, _positionno integer, _languageid character varying)
 RETURNS TABLE(departname character varying, positionname character varying)
 LANGUAGE plpgsql
AS $function$
#variable_conflict use_column
BEGIN

		CREATE TEMP TABLE _tmp (
				 DepartName varchar(100),
				 PositionName varchar(100)
				) ON COMMIT DROP;

		Insert into _tmp values ((Select case when _LanguageId = 'EN' then Dep.Name_EN else Dep.Name end from Organization_Departments as Dep where DepartNo = board_getdepartandpositionname._departno),
									(Select case when _LanguageId = 'EN' then Name_EN else Name end from Organization_Positions where PositionNo = board_getdepartandpositionname._positionno));

		RETURN QUERY
		select * from _tmp;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_insertandroiddevice(_userno integer, _regdate timestamp without time zone, _deviceid character varying, _osversion character varying, _notificationoptions character varying, _timezoneoffset integer)
