$function$

CREATE OR REPLACE FUNCTION public.board_insertboardcontent(_boardno integer, _moduserno integer, _modusername character varying, _modpositionno integer, _modpositionname character varying, _moddepartno integer, _moddepartname character varying, _regdate timestamp without time zone, _title character varying, _titleeffect integer, _groupno bigint, _depth integer, _orderno integer, _headno integer, _isnotice boolean, _content character varying, _isfile boolean, _filecount integer, _startdate timestamp without time zone, _enddate timestamp without time zone, _isshareall boolean, _type character varying, _errortype character varying, _persontype character varying, _designno character varying, _constructionname character varying, _applyto character varying, _important boolean, _mailrecipientno character varying, _mailrecipientname character varying, _private boolean, _purpose character varying, _note character varying, _other character varying, _inspector character varying, _generation character varying, _badno character varying, _standard character varying, _viewmode integer DEFAULT 2, _isalarm boolean DEFAULT false, _rootid integer DEFAULT 0, _visitdate timestamp without time zone DEFAULT NULL::timestamp without time zone, _visitcompletedate timestamp without time zone DEFAULT NULL::timestamp without time zone, _businessdate timestamp without time zone DEFAULT NULL::timestamp without time zone, _dateview timestamp without time zone DEFAULT NULL::timestamp without time zone)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _contentno bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	IF _GroupNo = 0 THEN

		_GroupNo := (SELECT MAX(GroupNo) + 1 FROM Board_Contents WHERE BoardNo = board_insertboardcontent._boardno);
		IF _GroupNo IS NULL THEN

			_GroupNo := 1;
		END IF;

	END IF;

	UPDATE Board_Contents SET OrderNo = OrderNo + 1
	WHERE BoardNo = board_insertboardcontent._boardno AND OrderNo >= board_insertboardcontent._orderno;

	INSERT INTO Board_Contents (BoardNo, ModUserNo, ModUserName, ModPositionNo, ModPositionName, ModDepartNo, ModDepartName,
		RegDate, ModDate, Title, TitleEffect, GroupNo, Depth, OrderNo, HeadNo, IsNotice, Content, IsFile, FileCount,
		ReplyCount, RecommendedCount, ViewedCount, StartDate, EndDate, Enabled,RegUserNo,  RegPositionNo,  RegDepartNo,ViewMode,IsAlarm,IsShareAll,Type,ErrorType,PersonType,DesignNo,ConstructionName,VisitDate,VisitCompleteDate,BusinessDate,DateView,ApplyTo,Important,MailRecipientNo,MailRecipientName,Private,Purpose,Note,Other,Inspector,Generation,BadNo,Standard)
	VALUES (_BoardNo, _ModUserNo, _ModUserName, _ModPositionNo, _ModPositionName, _ModDepartNo, _ModDepartName,
		_RegDate, _RegDate, _Title, _TitleEffect, _GroupNo, _Depth, _OrderNo, _HeadNo, _IsNotice, _Content, _IsFile, _FileCount,
		0, 0, 0, _StartDate, _EndDate, TRUE,_ModUserNo, _ModPositionNo, _ModDepartNo,_ViewMode,_IsAlarm,_IsShareAll,_Type,_ErrorType,_PersonType,_DesignNo,_ConstructionName,_VisitDate,_VisitCompleteDate,_BusinessDate,_DateView,_ApplyTo,_Important,_MailRecipientNo,_MailRecipientName,_Private,_Purpose,_Note,_Other,_Inspector,_Generation,_BadNo,_Standard);



	_ContentNo := lastval();
	IF _RootId=0 THEN
	    UPDATE Board_Contents SET RootId=_ContentNo WHERE ContentNo=_ContentNo;
	ELSE
	    UPDATE Board_Contents SET RootId=board_insertboardcontent._rootid WHERE ContentNo=_ContentNo;
	END IF;
	RETURN QUERY
	SELECT _ContentNo;
END;
$function$

