CREATE OR REPLACE FUNCTION public.board_upboard(_boardno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _parentno integer;
    _sortno integer;
    _tempno integer;
    _ranktempno integer;
BEGIN




SELECT FolderNo, SortNo INTO _parentno, _sortno FROM Board_Boards where BoardNo= board_upboard._boardno;
_RANKTEMPNO := 1;
FOR _tempno IN SELECT  BoardNo from Board_Boards WHERE _PARENTNO=FolderNo AND Enabled = TRUE ORDER BY SortNo ASC,BoardNo ASC LOOP
		UPDATE Board_Boards SET SortNo = _RANKTEMPNO WHERE _TEMPNO=BoardNo;

		IF _TEMPNO=board_upboard._boardno THEN
			_SORTNO := _RANKTEMPNO;
		END IF;
		_RANKTEMPNO := _RANKTEMPNO+1;
		   END LOOP;
UPDATE Board_Boards SET SortNo = _SORTNO WHERE _SORTNO = SortNo + 1 AND FolderNo=_PARENTNO AND Enabled = TRUE;
UPDATE Board_Boards SET SortNo = _SORTNO - 1 WHERE BoardNo= board_upboard._boardno;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_upboardbyuser(_boardno integer, _userno integer DEFAULT 70, _isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _curentno integer;
    _parentno integer;
    _downno integer;
    _isboard boolean;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

SELECT SortNo, FolderNo INTO _curentno, _parentno FROM Board_Boards WHERE  BoardNo = board_upboardbyuser._boardno;

SELECT T.SortNo, T.IsBoard INTO _downno, _isboard FROM (
SELECT BoardNo AS No, SortNo,TRUE AS IsBoard FROM Board_Boards B
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_upboardbyuser._userno
WHERE  B.Enabled = TRUE  AND (_IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo>_CurentNo AND _ParentNo=B.FolderNo
UNION ALL
SELECT BF.FolderNo AS No, SortNo,FALSE AS IsBoard
FROM  Board_Folders BF
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_upboardbyuser._userno
WHERE  BF.SortNo>_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled = TRUE AND (_IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
ORDER BY SortNo ASC) T ORDER BY T.SortNo ASC;











--SELECT SortNo, IsBoard INTO downno, isboard FROM TEMPUPDATE
IF _DownNo >0 AND _IsBoard= TRUE THEN
	UPDATE Board_Boards SET SortNo=_CurentNo WHERE SortNo=_DownNo;
	UPDATE Board_Boards SET SortNo=_DownNo WHERE BoardNo = board_upboardbyuser._boardno ;
IF _DownNo >0 AND _IsBoard= FALSE THEN
	UPDATE Board_Folders SET SortNo=_CurentNo WHERE SortNo=_DownNo;
	UPDATE Board_Boards SET SortNo=_DownNo WHERE BoardNo = board_upboardbyuser._boardno ;

END IF;
END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_updateallowaccess(_departno integer DEFAULT 49, _positionno integer DEFAULT 23, _userno integer DEFAULT 6656, _allowvalue integer DEFAULT 2, _itemno integer DEFAULT 137, _itemtype integer DEFAULT 1)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _no bigint;
    _value integer;
    _folderno integer;
    _prentaccessno bigint;
    _parentvalue integer;
    _folderno1 integer;
    _no1 bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF _ItemType=2 THEN
		DELETE FROM Board_AllowAccess
		WHERE UserNo = board_updateallowaccess._userno AND ItemNo=board_updateallowaccess._itemno AND ItemType= board_updateallowaccess._itemtype; -- AND DepartNo=DepartNo AND PositionNo= PositionNo
		IF _AllowValue >0 THEN
			INSERT INTO public."board_allowaccess"(DepartNo,PositionNo,UserNo,AllowValue,ItemNo,ItemType,ModDate,RegDate)
			VALUES(_DepartNo,_PositionNo,_UserNo,_AllowValue,_ItemNo,_ItemType,NOW(),NOW());
			CREATE TEMP TABLE FolderTemp1 ON COMMIT DROP AS WITH RECURSIVE FolderNos AS (
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo IN (SELECT FolderNo FROM Board_Boards where BoardNo=board_updateallowaccess._itemno AND PF.Enabled = TRUE)
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderNos FN ON FN.ParentNo = CF.FolderNo AND CF.Enabled = TRUE
			)
			SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.FolderNo FROM FolderNos F
			LEFT JOIN Board_AllowAccess BA ON BA.ItemType=1 AND BA.ItemNo=F.FolderNo AND BA.UserNo=board_updateallowaccess._userno;



			WHILE (Select Count(*) From FolderTemp1) > 0 LOOP
				SELECT AllowAccessNo, AllowValue, FolderNo INTO _no, _value, _folderno FROM FolderTemp1;
				IF _AllowValue >0 THEN
					IF _No=0 THEN
						INSERT INTO public."board_allowaccess"(DepartNo,PositionNo,UserNo,AllowValue,ItemNo,ItemType,ModDate,RegDate)
						SELECT _DepartNo,_PositionNo,_UserNo,_AllowValue,FT.FolderNo,1,NOW(),NOW() FROM FolderTemp1 FT;

					ELSE
						IF _AllowValue>_Value THEN
							RAISE NOTICE '%', _No;
							UPDATE Board_AllowAccess SET AllowValue=board_updateallowaccess._allowvalue,ModDate=NOW(),DepartNo=board_updateallowaccess._departno,PositionNo=board_updateallowaccess._positionno WHERE AllowAccessNo=_No;
						END IF;
					END IF;

				END IF;
				DELETE FROM FolderTemp1 Where FolderNo = _FolderNo;

			END LOOP;
		END IF;

	ELSE
		CREATE TEMP TABLE FolderParentTemp ON COMMIT DROP AS WITH RECURSIVE FolderParentNos AS (
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo =board_updateallowaccess._itemno
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderParentNos FN ON FN.ParentNo = CF.FolderNo AND CF.Enabled = TRUE
			)
		SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.FolderNo FROM FolderParentNos F
		LEFT JOIN Board_AllowAccess BA ON BA.ItemType=1 AND BA.ItemNo=F.FolderNo AND BA.UserNo=board_updateallowaccess._userno;



		WHILE (Select Count(*) From FolderParentTemp) > 0 LOOP

			SELECT AllowAccessNo, AllowValue, FolderNo INTO _prentaccessno, _parentvalue, _folderno1 FROM FolderParentTemp;
				IF _AllowValue >0 THEN
					IF _PrentAccessNo=0 THEN
						INSERT INTO public."board_allowaccess"(DepartNo,PositionNo,UserNo,AllowValue,ItemNo,ItemType,ModDate,RegDate)
						SELECT _DepartNo,_PositionNo,_UserNo,_AllowValue,FT.FolderNo,1,NOW(),NOW() FROM FolderParentTemp FT;

					ELSE
						--IF(AllowValue>Value)

						IF _AllowValue>_ParentValue THEN
							RAISE NOTICE '%', _No;
							UPDATE Board_AllowAccess SET AllowValue=board_updateallowaccess._allowvalue,ModDate=NOW(),DepartNo=board_updateallowaccess._departno,PositionNo=board_updateallowaccess._positionno WHERE AllowAccessNo=_PrentAccessNo;
						END IF;
					END IF;

				END IF;
				DELETE FROM FolderParentTemp Where FolderNo = _FolderNo1;
		END LOOP;
		CREATE TEMP TABLE FolderTemp ON COMMIT DROP AS WITH RECURSIVE FolderNos AS (
			SELECT     PF.FolderNo
			FROM       Board_Folders PF
			WHERE PF.FolderNo=board_updateallowaccess._itemno AND PF.Enabled = TRUE
			UNION ALL
			SELECT     CF.FolderNo
			FROM       Board_Folders CF
			INNER JOIN FolderNos FN ON FN.FolderNo = CF.ParentNo AND CF.Enabled = TRUE
		)
		---List FolderNo;;
		SELECT FolderNo FROM FolderNos;
		----List BoardNo
		CREATE TEMP TABLE BoardTemp ON COMMIT DROP AS SELECT BoardNo FROM Board_Boards
		WHERE Enabled = TRUE AND FolderNo IN (SELECT * FROM FolderTemp);

		WHILE (Select Count(*) From FolderTemp) > 0 LOOP
			SELECT FolderNo INTO _no1 FROM FolderTemp;
			IF _AllowValue >=0 THEN
