CREATE OR REPLACE FUNCTION public.board_updatedepartallowaccess(_departno integer DEFAULT 4, _allowvalue integer DEFAULT 2, _itemno integer DEFAULT 1160, _itemtype integer DEFAULT 2, _userno integer DEFAULT 70)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _no bigint;
    _value integer;
    _folderno integer;
    _prentaccessno bigint;
    _parentvalue integer;
    _folderno1 integer;
    _no1 bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	--UPDATE Board_DepartAllowAccess SET DepartNo=DepartNo,AllowValue=AllowValue , ItemNo=ItemNo,ItemType=ItemType,ModUserNo=UserNo,ModDate=NOW()
	--WHERE AllowAccessNo=AllowAccessNo
	--SELECT AllowAccessNo

	IF _ItemType=2 THEN
		DELETE FROM Board_DepartAllowAccess
		WHERE DepartNo = board_updatedepartallowaccess._departno AND ItemNo=board_updatedepartallowaccess._itemno AND ItemType= board_updatedepartallowaccess._itemtype;
		IF _AllowValue >0 THEN
			INSERT INTO public."board_departallowaccess"(DepartNo,AllowValue,ItemNo,ItemType,ModUserNo,ModDate,RegUserNo,RegDate)
			VALUES(_DepartNo,_AllowValue,_ItemNo,_ItemType,_UserNo,NOW(),_UserNo,NOW());
			CREATE TEMP TABLE FolderTemp1 ON COMMIT DROP AS WITH RECURSIVE FolderNos AS (
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo IN (SELECT FolderNo FROM Board_Boards where BoardNo=board_updatedepartallowaccess._itemno AND PF.Enabled = TRUE)
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderNos FN ON FN.ParentNo = CF.FolderNo AND CF.Enabled = TRUE
			)
			SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.FolderNo FROM FolderNos F
			LEFT JOIN Board_DepartAllowAccess BA ON BA.ItemType=1 AND BA.ItemNo=F.FolderNo AND BA.DepartNo=board_updatedepartallowaccess._departno;



			WHILE (Select Count(*) From FolderTemp1) > 0 LOOP
				SELECT AllowAccessNo, AllowValue, FolderNo INTO _no, _value, _folderno FROM FolderTemp1;
				IF _AllowValue >0 THEN
					IF _No=0 THEN
						INSERT INTO  public."board_departallowaccess"(DepartNo,AllowValue,ItemNo,ItemType,ModUserNo,ModDate,RegUserNo,RegDate)
						SELECT _DepartNo,_AllowValue,FT.FolderNo,1,_UserNo,NOW(),_UserNo,NOW() FROM FolderTemp1 FT;

					ELSE
						IF _AllowValue>_Value THEN
							RAISE NOTICE '%', _No;
							UPDATE Board_DepartAllowAccess SET AllowValue=board_updatedepartallowaccess._allowvalue,ModUserNo=board_updatedepartallowaccess._userno,ModDate=NOW(),DepartNo=board_updatedepartallowaccess._departno WHERE AllowAccessNo=_No;
						END IF;
					END IF;

				END IF;
				DELETE FROM FolderTemp1 Where FolderNo = _FolderNo;

			END LOOP;
		END IF;

	ELSE
		CREATE TEMP TABLE FolderParentTemp ON COMMIT DROP AS WITH RECURSIVE FolderParentNos AS (
				SELECT     PF.FolderNo , PF.ParentNo
				FROM       Board_Folders PF

				WHERE PF.FolderNo =board_updatedepartallowaccess._itemno
				UNION ALL
				SELECT     CF.FolderNo , CF.ParentNo
				FROM       Board_Folders CF
				INNER JOIN FolderParentNos FN ON FN.ParentNo = CF.FolderNo AND CF.Enabled = TRUE
			)
		SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.FolderNo FROM FolderParentNos F
		LEFT JOIN Board_DepartAllowAccess BA ON BA.ItemType=1 AND BA.ItemNo=F.FolderNo AND BA.DepartNo=board_updatedepartallowaccess._departno;



		WHILE (Select Count(*) From FolderParentTemp) > 0 LOOP

			SELECT AllowAccessNo, AllowValue, FolderNo INTO _prentaccessno, _parentvalue, _folderno1 FROM FolderParentTemp;
				IF _AllowValue >0 THEN
					IF _PrentAccessNo=0 THEN
						INSERT INTO public."board_departallowaccess"(DepartNo,AllowValue,ItemNo,ItemType,ModUserNo,ModDate,RegUserNo,RegDate)
						SELECT _DepartNo,_AllowValue,FT.FolderNo,1,_UserNo,NOW(),_UserNo,NOW() FROM FolderParentTemp FT;

					ELSE
						--IF(AllowValue>Value)

						IF _AllowValue>_ParentValue THEN
							RAISE NOTICE '%', _No;
							UPDATE Board_DepartAllowAccess SET AllowValue=board_updatedepartallowaccess._allowvalue,ModDate=NOW(),DepartNo=board_updatedepartallowaccess._departno,ModUserNo=board_updatedepartallowaccess._userno WHERE AllowAccessNo=_PrentAccessNo;
						END IF;
					END IF;

				END IF;
				DELETE FROM FolderParentTemp Where FolderNo = _FolderNo1;
		END LOOP;
		CREATE TEMP TABLE FolderTemp ON COMMIT DROP AS WITH RECURSIVE FolderNos AS (
			SELECT     PF.FolderNo
			FROM       Board_Folders PF
			WHERE PF.FolderNo=board_updatedepartallowaccess._itemno AND PF.Enabled = TRUE
			UNION ALL
			SELECT     CF.FolderNo
			FROM       Board_Folders CF
			INNER JOIN FolderNos FN ON FN.FolderNo = CF.ParentNo AND CF.Enabled = TRUE
		)
		---List FolderNo;;
		SELECT FolderNo FROM FolderNos;
		----List BoardNo
		CREATE TEMP TABLE BoardTemp ON COMMIT DROP AS SELECT BoardNo FROM Board_Boards
		WHERE Enabled = TRUE AND FolderNo IN (SELECT * FROM FolderTemp);

		WHILE (Select Count(*) From FolderTemp) > 0 LOOP
			SELECT FolderNo INTO _no1 FROM FolderTemp;
			IF _AllowValue >=0 THEN
				IF (SELECT COUNT(AllowAccessNo) FROM Board_DepartAllowAccess WHERE ItemType=1 AND ItemNo=_No1 AND DepartNo=board_updatedepartallowaccess._departno)>0 THEN
					--Print No1;
					UPDATE Board_DepartAllowAccess SET AllowValue=board_updatedepartallowaccess._allowvalue,DepartNo=board_updatedepartallowaccess._departno,ModUserNo=board_updatedepartallowaccess._userno ,ModDate=NOW() WHERE ItemType=1 AND ItemNo=_No1 AND DepartNo=board_updatedepartallowaccess._departno;
				ELSE
					INSERT INTO public."board_departallowaccess"(DepartNo,AllowValue,ItemNo,ItemType,ModUserNo,ModDate,RegUserNo,RegDate)
					VALUES(_DepartNo,_AllowValue,_No1,1,_UserNo,NOW(),_UserNo,NOW());
				END IF;

			END IF;

			DELETE FROM FolderTemp Where FolderNo = _No1;

		END LOOP;
		WHILE (Select Count(*) From BoardTemp) > 0 LOOP
			SELECT BoardNo INTO _no1 FROM BoardTemp;
			--Print AllowValue
			--DELETE FROM Board_DepartAllowAccess
			--WHERE UserNo = UserNo AND ItemNo=No AND ItemType= 2
			IF _AllowValue >=0 THEN
				IF (SELECT COUNT(AllowAccessNo) FROM Board_DepartAllowAccess WHERE ItemType=2 AND ItemNo=_No1 AND DepartNo=board_updatedepartallowaccess._departno )>0 THEN
					--Print  No1;
					UPDATE Board_DepartAllowAccess SET AllowValue=board_updatedepartallowaccess._allowvalue,DepartNo=board_updatedepartallowaccess._departno,ModUserNo=board_updatedepartallowaccess._userno,ModDate=NOW()  WHERE ItemType=2 AND ItemNo=_No1 AND DepartNo=board_updatedepartallowaccess._departno;
				ELSE
					INSERT INTO public."board_departallowaccess"(DepartNo,AllowValue,ItemNo,ItemType,ModUserNo,ModDate,RegUserNo,RegDate)
					VALUES(_DepartNo,_AllowValue,_No1,2,_UserNo,NOW(),_UserNo,NOW());
				END IF;
			END IF;
			DELETE FROM BoardTemp Where BoardNo = _No1;
		END LOOP;
	END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_updatelevelrand(_parentid integer, _parentrand character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _folderno integer;
    _levelrand character varying;
BEGIN


	IF _ParentId = 0 THEN
		UPDATE Board_Folders SET LevelRand =  ',' WHERE ParentNo= board_updatelevelrand._parentid;
	ELSE
		UPDATE Board_Folders SET LevelRand = board_updatelevelrand._parentrand  || CAST(_ParentId AS text) || ',' WHERE ParentNo= board_updatelevelrand._parentid;
	END IF;






		FOR _folderno, _levelrand IN SELECT FolderNo,LevelRand FROM Board_Folders WHERE ParentNo= board_updatelevelrand._parentid LOOP


		PERFORM board_updatelevelrand(_FolderNo, _LevelRand);

			END LOOP;
END;
$function$

