CREATE OR REPLACE FUNCTION public.board_upfolder(_folderno integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _parentno integer;
    _sortno integer;
    _foldertempno integer;
    _ranktempno integer;
BEGIN




SELECT ParentNo, SortNo INTO _parentno, _sortno FROM Board_Folders where FolderNo= board_upfolder._folderno;
_RANKTEMPNO := 1;
FOR _foldertempno IN SELECT FolderNo from Board_Folders WHERE _PARENTNO=ParentNo AND Enabled = TRUE ORDER BY SortNo ASC, FolderNo ASC LOOP
		UPDATE Board_Folders SET SortNo = _RANKTEMPNO WHERE _FOLDERTEMPNO=FolderNo;

		IF _FOLDERTEMPNO=board_upfolder._folderno THEN
			_SORTNO := _RANKTEMPNO;
		END IF;

		_RANKTEMPNO := _RANKTEMPNO + 1;
		   END LOOP;
UPDATE Board_Folders SET SortNo = _SORTNO WHERE _SORTNO = SortNo + 1 AND ParentNo=_PARENTNO AND Enabled = TRUE;
UPDATE Board_Folders SET SortNo = _SORTNO-1 WHERE FolderNo = board_upfolder._folderno;
END;
$function$

CREATE OR REPLACE FUNCTION public.board_upfolderbyuser(_folderno integer DEFAULT 116, _userno integer DEFAULT 70, _isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _curentno integer;
    _parentno integer;
    _downno integer;
    _isfolder boolean;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

SELECT SortNo, ParentNo INTO _curentno, _parentno FROM Board_Folders WHERE  FolderNo = board_upfolderbyuser._folderno;

SELECT T.SortNo, T.IsFolder INTO _downno, _isfolder FROM (
SELECT BoardNo AS No, SortNo,FALSE AS IsFolder FROM Board_Boards B
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_upfolderbyuser._userno
WHERE  B.Enabled = TRUE  AND (_IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL) AND B.SortNo>_CurentNo AND _ParentNo=B.FolderNo
UNION ALL
SELECT BF.FolderNo AS No, SortNo,TRUE AS IsFolder
FROM  Board_Folders BF
LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_upfolderbyuser._userno
WHERE  BF.SortNo>_CurentNo AND _ParentNo=BF.ParentNo AND BF.Enabled = TRUE AND (_IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue>0 )
ORDER BY SortNo ASC) T ORDER BY T.SortNo ASC;











--SELECT SortNo, IsBoard INTO downno, isboard FROM TEMPUPDATE
IF _DownNo >0 AND _IsFolder= TRUE THEN
	UPDATE Board_Folders SET SortNo=_CurentNo WHERE SortNo=_DownNo;
	UPDATE Board_Folders SET SortNo=_DownNo WHERE FolderNo = board_upfolderbyuser._folderno ;
IF _DownNo >0 AND _IsFolder= FALSE THEN
	UPDATE Board_Boards SET SortNo=_CurentNo WHERE SortNo=_DownNo;
	UPDATE Board_Folders SET SortNo=_DownNo WHERE FolderNo = board_upfolderbyuser._folderno ;

END IF;
END IF;
END;
$function$

