CREATE OR REPLACE FUNCTION public.contacts_deleteaddressall(_userno integer, _seq integer, _mode integer DEFAULT 1)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF _Mode = 0 THEN -- 완전삭제

		PERFORM contacts_savecontactshistory(_UserNo, _Seq, 'DEL');

		DELETE FROM ContactsNumber WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsEmail WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsDays WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsCompany WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsAddress WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsSns WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsGroupUser WHERE RegUserNo=contacts_deleteaddressall._userno AND UserSeq=contacts_deleteaddressall._seq;
		DELETE FROM ContactsUser WHERE RegUserNo=contacts_deleteaddressall._userno AND Seq=contacts_deleteaddressall._seq;
	ELSE
		UPDATE ContactsUser
		SET
			UseYn = '',
			ModDate = NOW(),
			DelDate = NOW()
		WHERE RegUserNo=contacts_deleteaddressall._userno AND Seq=contacts_deleteaddressall._seq;
	END IF;
END;
$function$

