CREATE OR REPLACE FUNCTION public.contacts_deletedepartallowaccess(_listallowaccessno character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _departno integer;
    _itemno integer;
BEGIN


	CREATE TEMP TABLE Contact_DepartAllowAccess ON COMMIT DROP AS SELECT * FROM Contact_DepartAllowAccess
	WHERE AllowAccessNo IN(SELECT unnest(string_to_array(_ListAllowAccessNo, ','))::integer);



	WHILE (Select Count(*) From Contact_DepartAllowAccess) > 0 LOOP
			SELECT DA.DepartNo, DA.ItemNo INTO _departno, _itemno FROM Contact_DepartAllowAccess DA;
			CREATE TEMP TABLE ShareGroupTemp ON COMMIT DROP AS WITH RECURSIVE ShareGroupNos AS (
				SELECT     PF.ShareGroupNo , PF.ParentNo
				FROM       Contact_ShareGroup PF

				WHERE PF.ShareGroupNo =_ItemNo
				UNION ALL
				SELECT     CF.ShareGroupNo , CF.ParentNo
				FROM       Contact_ShareGroup CF
				INNER JOIN ShareGroupNos FN ON FN.ShareGroupNo = CF.ParentNo AND CF.IsDelete = FALSE
			)
			SELECT * FROM ShareGroupNos;

			DELETE FROM Contact_DepartAllowAccess WHERE DepartNo=_DepartNo AND ItemNo IN (SELECT BB.ShareGroupNo FROM Contact_ShareGroup BB INNER JOIN ShareGroupTemp BF ON BF.ShareGroupNo=bb.ShareGroupNo);

			DROP TABLE IF EXISTS ShareGroupTemp;

