CREATE OR REPLACE FUNCTION public.contacts_getusergroup(_reguserno integer, _userno integer, _groupno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _groupname character varying;
    _groupcount integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN




	IF _GroupNo = 0 THEN
		SELECT b.GroupName INTO _groupname FROM ContactsGroupUser a
		INNER JOIN ContactsGroup b ON a.GroupNo=b.GroupNo
		WHERE a.UserSeq=contacts_getusergroup._userno AND a.RegUserNo=contacts_getusergroup._reguserno;
	ELSE
		SELECT b.GroupName INTO _groupname FROM ContactsGroupUser a
		INNER JOIN ContactsGroup b ON a.GroupNo=b.GroupNo
		WHERE a.UserSeq=contacts_getusergroup._userno AND a.RegUserNo=contacts_getusergroup._reguserno AND a.GroupNo IN (select TreeID from public."getchildgroup"(_RegUserNo,_GroupNo));
	END IF;

	SELECT COUNT(*) INTO _groupcount FROM ContactsGroupUser
	WHERE UserSeq=contacts_getusergroup._userno AND RegUserNo=contacts_getusergroup._reguserno;

	IF _GroupCount = 1 THEN
		RETURN QUERY
		SELECT COALESCE(_GroupName,'');
	ELSE
		RETURN QUERY
		SELECT COALESCE(_GroupName,'') || ';' || CAST(_GroupCount - 1 AS text);
	END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.contacts_insertgroup(_userno integer, _grpname character varying, _parentno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _sort integer;
    _groupno integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	SELECT Sort INTO _sort FROM ContactsGroup
	WHERE RegUserNo = contacts_insertgroup._userno AND ParentGNo = contacts_insertgroup._parentno
	ORDER BY Sort DESC;

	INSERT INTO ContactsGroup (GroupName, ParentGNo, RegUserNo, Sort,RegDate,IsDefault,UseYn)
	VALUES (_GrpName, _ParentNo, _UserNo, _Sort+1,NOW(),'0','Y');

	_GroupNo := lastval();
	RETURN QUERY
	SELECT _GroupNo AS GroupNo;
END;
$function$

