CREATE OR REPLACE FUNCTION public.contacts_movecontactgroup(_userno integer DEFAULT 70, _groupno integer DEFAULT 644, _newparentno integer DEFAULT 627, _position integer DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _sort integer;
    _tempno integer;
BEGIN


_Sort := 0;
FOR _tempno IN SELECT  GroupNo from ContactsGroup WHERE RegUserNo=contacts_movecontactgroup._userno AND ParentGNo=contacts_movecontactgroup._newparentno AND UseYn='Y'  ORDER BY Sort ASC LOOP
		RAISE NOTICE '%', _TEMPNO;
		IF _Sort<contacts_movecontactgroup._position THEN
			RAISE NOTICE '%', _Sort;
			UPDATE ContactsGroup SET Sort = _Sort WHERE GroupNo=_TEMPNO;
		END IF;
		IF _Sort=contacts_movecontactgroup._position THEN
			RAISE NOTICE '%', _Sort;
			UPDATE ContactsGroup SET Sort = _Sort ,ParentGNo=contacts_movecontactgroup._newparentno WHERE GroupNo=contacts_movecontactgroup._groupno;
			UPDATE ContactsGroup SET Sort = _Sort+1 WHERE GroupNo=_TEMPNO;
		END IF;
		IF _Sort>contacts_movecontactgroup._position THEN
			RAISE NOTICE '%', _Sort;
			UPDATE ContactsGroup SET Sort = _Sort+1 WHERE _TEMPNO=GroupNo;
		END IF;
		_Sort := _Sort+1;
		   END LOOP;
END;
$function$

