CREATE OR REPLACE FUNCTION public.contacts_setaddress(_reguserno integer, _userseq integer, _type smallint, _typename character varying, _zipcode1 character varying, _zipcode2 character varying, _address character varying, _isdefault character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF _Address IS NOT NULL THEN
		IF LENGTH(_Address) > 0 THEN
			INSERT INTO ContactsAddress(RegUserNo,UserSeq,Type,TypeName,ZipCode1,ZipCode2,Address,IsDefault)
			VALUES(_RegUserNo,_UserSeq,_Type,_TypeName,_ZipCode1,_ZipCode2,_Address,_IsDefault);
		END IF;
	END IF;
END;
