CREATE OR REPLACE FUNCTION public.contacts_setcontactsgroup(_groupno integer, _groupname character varying, _reguserno integer, _memo character varying, _mode character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    _sort integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF _Mode = '0' THEN

		SELECT COUNT(*) + 1 INTO _sort FROM ContactsGroup WHERE RegUserNo=contacts_setcontactsgroup._reguserno AND ParentGNo=contacts_setcontactsgroup._groupno;

		INSERT INTO ContactsGroup(GroupName, RegUserNo, RegDate, Memo,ParentGNo,Sort, IsDefault)
		VALUES(_GroupName, _RegUserNo, NOW(), _Memo, _GroupNo, _Sort , '0');
	ELSIF _Mode = '1' THEN
		UPDATE ContactsGroup SET GroupName=contacts_setcontactsgroup._groupname WHERE GroupNo=contacts_setcontactsgroup._groupno;
	ELSE
		UPDATE ContactsGroup SET Memo=contacts_setcontactsgroup._memo WHERE GroupNo=contacts_setcontactsgroup._groupno;
	END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.contacts_setcontactsrestore(_reguserno integer, _userno character varying, _groupno character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	UPDATE ContactsUser SET UseYn='Y' WHERE Seq=contacts_setcontactsrestore._userno AND RegUserNo=contacts_setcontactsrestore._reguserno;
	UPDATE ContactsGroupUser SET GroupNo=contacts_setcontactsrestore._groupno WHERE UserSeq=contacts_setcontactsrestore._userno AND RegUserNo=contacts_setcontactsrestore._reguserno;
END;
