	(GroupNo,UserSeq,RegUserNo,RegDate,ModDate)
	SELECT GroupNo, UserSeq, RegUserNo, NOW(), NOW() FROM _tab;

	RETURN QUERY
	SELECT _RTN;
END;
$function$

