CREATE OR REPLACE FUNCTION public.contacts_updatecontactsuser(_reguserno integer, _userseq integer, _memo character varying, _share character varying, _groupno character varying, _company character varying, _zipcode1 character varying, _zipcode2 character varying, _address character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	DELETE FROM ContactsGroupUser WHERE UserSeq = contacts_updatecontactsuser._userseq;

	UPDATE ContactsUser SET Memo = contacts_updatecontactsuser._memo, RegDate = NOW(), Share = contacts_updatecontactsuser._share
		WHERE RegUserNo = contacts_updatecontactsuser._reguserno AND Seq = contacts_updatecontactsuser._userseq;

	CREATE TEMP TABLE _tab (GroupNo INT,ContactsUser INT,RegUserNo INT) ON COMMIT DROP;
	WHILE STRPOS(_GroupNo, ',') > 0 LOOP
		INSERT INTO _tab(GroupNo,ContactsUser,RegUserNo)
		VALUES (COALESCE(NULLIF((SUBSTRING(_GroupNo,0,STRPOS(_GroupNo, ',')))::text, '')::integer, 0),_UserSeq,_RegUserNo);
		_GroupNo := SUBSTRING(_GroupNo,STRPOS(_GroupNo, ',')+1,LENGTH(_GroupNo));
	END LOOP;

	INSERT INTO _tab VALUES (COALESCE(NULLIF((_GroupNo)::text, '')::integer, 0),_UserSeq,_RegUserNo);
	INSERT INTO ContactsGroupUser (GroupNo, UserSeq, RegUserNo, RegDate) SELECT *,NOW() FROM _tab;

	UPDATE ContactsCompany SET Company = contacts_updatecontactsuser._company WHERE RegUserNo = contacts_updatecontactsuser._reguserno AND UserSeq = contacts_updatecontactsuser._userseq;

	UPDATE ContactsAddress SET ZipCode1 = contacts_updatecontactsuser._zipcode1, ZipCode2 = contacts_updatecontactsuser._zipcode2, Address = contacts_updatecontactsuser._address WHERE RegUserNo = contacts_updatecontactsuser._reguserno AND UserSeq = contacts_updatecontactsuser._userseq;
END;
$function$

CREATE OR REPLACE FUNCTION public.contacts_updatedepartallowaccess(_departno integer DEFAULT 4, _allowvalue integer DEFAULT 2, _itemno integer DEFAULT 16, _userno integer DEFAULT 70)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _prentaccessno bigint;
    _parentvalue integer;
    _sharegroupno1 integer;
    _no1 bigint;
BEGIN


	--UPDATE Contacts_DepartAllowAccess SET DepartNo=DepartNo,AllowValue=AllowValue , ItemNo=ItemNo,ItemType=ItemType,ModUserNo=UserNo,ModDate=NOW()
	--WHERE AllowAccessNo=AllowAccessNo
	--SELECT AllowAccessNo


		CREATE TEMP TABLE FolderParentTemp ON COMMIT DROP AS WITH RECURSIVE GroupTmp AS (
				SELECT     PF.ShareGroupNo , PF.ParentNo
				FROM       Contact_ShareGroup PF

				WHERE PF.ShareGroupNo =contacts_updatedepartallowaccess._itemno
				UNION ALL
				SELECT     CF.ShareGroupNo , CF.ParentNo
				FROM       Contact_ShareGroup CF
				INNER JOIN GroupTmp FN ON FN.ParentNo = CF.ShareGroupNo AND CF.IsDelete = FALSE

		),GroupParentNos AS(
			SELECT 0 AS ShareGroupNo,-1 AS ParentNo
			UNION ALL
			SELECT     PF.ShareGroupNo , PF.ParentNo
				FROM       GroupTmp PF
		)
		SELECT COALESCE(BA.AllowAccessNo,0)AS AllowAccessNo ,COALESCE(BA.AllowValue,0) AS AllowValue,F.ShareGroupNo FROM GroupParentNos F
		LEFT JOIN Contact_DepartAllowAccess BA ON BA.ItemNo=F.ShareGroupNo AND BA.DepartNo=contacts_updatedepartallowaccess._departno;



		WHILE (Select Count(*) From FolderParentTemp) > 0 LOOP

			SELECT AllowAccessNo, AllowValue, ShareGroupNo INTO _prentaccessno, _parentvalue, _sharegroupno1 FROM FolderParentTemp;
				IF _AllowValue >0 THEN
					IF _PrentAccessNo=0 THEN
						INSERT INTO public."contact_departallowaccess"(DepartNo,AllowValue,ItemNo,ModUserNo,ModDate,RegUserNo,RegDate)
						SELECT _DepartNo,_AllowValue,FT.ShareGroupNo,_UserNo,NOW(),_UserNo,NOW() FROM FolderParentTemp FT;

					ELSE
						--IF(AllowValue>Value)

						IF _AllowValue>_ParentValue THEN

							UPDATE Contact_DepartAllowAccess SET AllowValue=contacts_updatedepartallowaccess._allowvalue,ModDate=NOW(),DepartNo=contacts_updatedepartallowaccess._departno,ModUserNo=contacts_updatedepartallowaccess._userno WHERE AllowAccessNo=_PrentAccessNo;
						END IF;
					END IF;

				END IF;
				DELETE FROM FolderParentTemp Where ShareGroupNo = _ShareGroupNo1;
		END LOOP;
		CREATE TEMP TABLE GroupTemp ON COMMIT DROP AS WITH RECURSIVE ShareGroupNos AS (
			SELECT     PF.ShareGroupNo
			FROM       Contact_ShareGroup PF
			WHERE PF.ShareGroupNo=contacts_updatedepartallowaccess._itemno AND PF.IsDelete = FALSE
			UNION ALL
			SELECT     CF.ShareGroupNo
			FROM       Contact_ShareGroup CF
			INNER JOIN ShareGroupNos FN ON FN.ShareGroupNo = CF.ParentNo AND CF.IsDelete = FALSE
		)
		---List ShareGroupNo
		SELECT ShareGroupNo FROM ShareGroupNos;
		----List BoardNo

		WHILE (Select Count(*) From GroupTemp) > 0 LOOP
			SELECT ShareGroupNo INTO _no1 FROM GroupTemp;
			IF _AllowValue >=0 THEN
				IF (SELECT COUNT(AllowAccessNo) FROM Contact_DepartAllowAccess WHERE  ItemNo=_No1 AND DepartNo=contacts_updatedepartallowaccess._departno)>0 THEN
					--Print No1;
					UPDATE Contact_DepartAllowAccess SET AllowValue=contacts_updatedepartallowaccess._allowvalue,DepartNo=contacts_updatedepartallowaccess._departno,ModUserNo=contacts_updatedepartallowaccess._userno ,ModDate=NOW() WHERE ItemNo=_No1 AND DepartNo=contacts_updatedepartallowaccess._departno;
				ELSE
					INSERT INTO public."board_departallowaccess"(DepartNo,AllowValue,ItemNo,ItemType,ModUserNo,ModDate,RegUserNo,RegDate)
					VALUES(_DepartNo,_AllowValue,_No1,1,_UserNo,NOW(),_UserNo,NOW());
				END IF;

			END IF;

			DELETE FROM GroupTemp Where ShareGroupNo = _No1;

		END LOOP;
END;
$function$

